company_id = #{companyId}, title = #{title}, city = #{city}, experience = #{experience}, education = #{education}, min_salary = #{minSalary}, max_salary = #{maxSalary}, salary_unit = #{salaryUnit}, skills = #{skills}, job_desc = #{jobDesc}, publish_time = #{publishTime},
