mapper.select:
SELECT j.* FROM job j LEFT JOIN company c ON j.company_id = c.id
AND (j.title LIKE CONCAT('%', #{keyword}, '%') OR j.skills LIKE CONCAT('%', #{keyword}, '%') OR j.job_desc LIKE CONCAT('%', #{keyword}, '%'))
AND j.city = #{city}
AND c.name LIKE CONCAT('%', #{companyName}, '%')
AND j.experience = #{experience}
AND j.education = #{education}
ORDER BY j.publish_time DESC

SELECT AVG((min_salary + max_salary) / 2) AS avgSalary
FROM job


        AND city = #{city}


        AND experience = #{experience}


        AND education = #{education}


        AND skills LIKE CONCAT('%', #{skills}, '%')
